const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

function main() {
    let inputLines = [];

    rl.on('line', (line) => {
        inputLines.push(line.trim());
    });

    rl.on('close', () => {
        const N = parseInt(inputLines[0]);
        const arr = inputLines[1].split(' ').map(Number);

        const prefixSums = [];
        let currentSum = 0;

        for (let i = 0; i < N; i++) {
            currentSum += arr[i];
            prefixSums.push(currentSum);
        }

        console.log(prefixSums.join(' '));
    });
}

main();
